"use strict";(self.webpackChunk=self.webpackChunk||[]).push([[3858],{7162:(e,a,r)=>{r.r(a),r.d(a,{data:()=>n});const n={key:"v-54a128a0",path:"/web/Monorepo.html",title:"Monorepo 架构",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"什么是 Monorepo",slug:"什么是-monorepo",children:[]},{level:2,title:"lerna",slug:"lerna",children:[]},{level:2,title:"安装",slug:"安装",children:[]},{level:2,title:"初始化仓库/项目",slug:"初始化仓库-项目",children:[]}],filePathRelative:"web/Monorepo.md",git:{updatedTime:1673191741e3,contributors:[{name:"lbz",email:"905808069@qq.com",commits:1}]}}},4693:(e,a,r)=>{r.r(a),r.d(a,{default:()=>l});const n=(0,r(6252).uE)('<h1 id="monorepo-架构" tabindex="-1"><a class="header-anchor" href="#monorepo-架构" aria-hidden="true">#</a> Monorepo 架构</h1><h2 id="什么是-monorepo" tabindex="-1"><a class="header-anchor" href="#什么是-monorepo" aria-hidden="true">#</a> 什么是 Monorepo</h2><p>Monorepo 是一种代码组织思想，它要求我们只用一个代码仓库来管理一个大项目的所有资源、子项目。简单来说以前放在多个 repo 里的代码现在就放在一个 repo 就行了。 Multirepo (传统多repo 项目)会将一个项目按照职责、业务模块进行拆分，然后创建不同的代码仓库进行管理。不同的团队可以专注于负责某一个代码仓库代码提交、编译、发布。</p><h2 id="lerna" tabindex="-1"><a class="header-anchor" href="#lerna" aria-hidden="true">#</a> lerna</h2><p>Lerna 是一个管理工具，用于管理包含多个软件包 (package)的JavaScript 项目，使用git和npm管理多软件包代码仓库的工作流程进行优化。</p><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h2><div class="language-text ext-text line-numbers-mode"><pre class="shiki" style="background-color:#1E1E1E;"><code><span class="line"><span style="color:#D4D4D4;">npm install --global lerna\n</span></span></code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="初始化仓库-项目" tabindex="-1"><a class="header-anchor" href="#初始化仓库-项目" aria-hidden="true">#</a> 初始化仓库/项目</h2>',8),o={},l=(0,r(3744).Z)(o,[["render",function(e,a){return n}]])}}]);